"use client";

export { Overflow, type OverflowProps } from "./overflow";
export type { OverflowIndicatorRender, OverflowIndicatorRenderProps } from "./overflow-items";

"use client";

import type { ComponentPropsWithRef, ReactNode } from "react";
import { type OverflowIndicatorRender, OverflowItems } from "./overflow-items";
import { OverflowText } from "./overflow-text";

/** Props for div root. */
type DivRootProps = Omit<ComponentPropsWithRef<"div">, "children">;

/** Props for overflow text. */
type OverflowTextProps = DivRootProps & {
  mode?: "text";
  lines?: number;
  tooltip?: ReactNode | boolean;
  gap?: never;
  indicator?: never;
  children: string;
};

/** Props for overflow items. */
type OverflowItemsProps = DivRootProps & {
  mode: "items";
  lines?: never;
  tooltip?: never;
  gap?: string;
  indicator?: OverflowIndicatorRender;
  children: ReactNode;
};

/** Props for overflow. */
export type OverflowProps = OverflowTextProps | OverflowItemsProps;

/** Root - text mode by default; set mode="items" for fitting child items. */
export function Overflow({ mode, children, ...rest }: OverflowProps) {
  if (mode === "items") {
    return <OverflowItems {...rest}>{children}</OverflowItems>;
  }

  return <OverflowText {...rest}>{children}</OverflowText>;
}

"use client";

import type { ComponentPropsWithRef, CSSProperties, ReactNode, Ref } from "react";
import { useComposedRefs } from "@/hooks/use-composed-refs";
import { useOverflowDetection } from "@/hooks/use-overflow-detection";
import { cn } from "@/lib/utils";
import {
  type PopoverTriggerRenderProps,
  PopoverTrigger as TooltipTrigger,
} from "../popover/popover-trigger";
import { TooltipRoot as Tooltip } from "../tooltip/tooltip";
import { TooltipContent } from "../tooltip/tooltip-content";

function resolveTooltipContent(
  tooltip: ReactNode | boolean | undefined,
  children: string,
): ReactNode | null {
  if (tooltip === false) return null;
  if (tooltip != null && tooltip !== true) return tooltip;
  return children;
}

/** Props for overflow text. */
export interface OverflowTextProps extends Omit<ComponentPropsWithRef<"div">, "children"> {
  /** String to clamp (text mode) or items to measure (items mode). */
  children: string;
  /** Text mode only. 1 truncates; 2+ uses CSS line-clamp. */
  lines?: number;
  /**
   * Text mode only. true/ReactNode renders a Tooltip when content is actually clipped
   * (auto-derived from children when true). false disables the tooltip.
   */
  tooltip?: ReactNode | boolean;
}

function clampStyle(lines: number): CSSProperties | undefined {
  if (lines <= 1) return undefined;
  return {
    display: "-webkit-box",
    WebkitLineClamp: lines,
    WebkitBoxOrient: "vertical",
    overflow: "hidden",
  };
}

type PassiveOverflowTriggerProps = Pick<
  PopoverTriggerRenderProps,
  | "ref"
  | "className"
  | "aria-describedby"
  | "onPointerDown"
  | "onMouseEnter"
  | "onMouseLeave"
  | "onFocus"
  | "onBlur"
  | "tabIndex"
>;

/** Props for overflow tooltip trigger. */
interface OverflowTooltipTriggerProps extends PassiveOverflowTriggerProps {
  /** Ref for the container element. */
  containerRef: Ref<HTMLDivElement>;
  /** Text mode only. 1 truncates; 2+ uses CSS line-clamp. */
  lines: number;
  /** Additional class names merged onto the rendered element. */
  className?: string;
  /** Inline styles applied to the rendered element. */
  style: CSSProperties | undefined;
  /** Props forwarded to the container element. */
  containerProps: Omit<ComponentPropsWithRef<"div">, "children">;
  /** String to clamp (text mode) or items to measure (items mode). */
  children: string;
}

function OverflowTooltipTrigger({
  ref: triggerRef,
  className: triggerClassName,
  containerRef,
  lines,
  className,
  style,
  containerProps,
  children,
  ...restTrigger
}: OverflowTooltipTriggerProps) {
  const composedRef = useComposedRefs(containerRef, triggerRef);
  return (
    <div
      ref={composedRef}
      data-slot="overflow"
      className={cn(lines === 1 && "truncate", className, triggerClassName)}
      style={style}
      {...containerProps}
      {...restTrigger}
    >
      {children}
    </div>
  );
}

/** Root - text mode by default; set mode="items" for fitting child items. */
export function OverflowText({
  children,
  lines = 1,
  tooltip,
  className,
  ref: forwardedRef,
  ...props
}: OverflowTextProps) {
  const { ref, isOverflowing } = useOverflowDetection<HTMLDivElement>(
    lines > 1 ? "vertical" : "horizontal",
  );
  const composedRef = useComposedRefs(ref, forwardedRef);

  const resolvedTooltip = resolveTooltipContent(tooltip, children);
  const style = clampStyle(lines);
  const content = (
    <div
      ref={composedRef}
      data-slot="overflow"
      className={cn(lines === 1 && "truncate", className)}
      style={style}
      {...props}
    >
      {children}
    </div>
  );

  if (resolvedTooltip != null) {
    return (
      <Tooltip enabled={isOverflowing}>
        <TooltipTrigger>
          {(triggerProps: PopoverTriggerRenderProps) => {
            const passiveTriggerProps = {
              ref: triggerProps.ref,
              className: triggerProps.className,
              "aria-describedby": triggerProps["aria-describedby"],
              onPointerDown: triggerProps.onPointerDown,
              onMouseEnter: triggerProps.onMouseEnter,
              onMouseLeave: triggerProps.onMouseLeave,
              onFocus: triggerProps.onFocus,
              onBlur: triggerProps.onBlur,
              tabIndex: triggerProps.tabIndex,
            } satisfies PassiveOverflowTriggerProps;

            return (
              <OverflowTooltipTrigger
                {...passiveTriggerProps}
                containerRef={composedRef}
                lines={lines}
                className={className}
                style={style}
                containerProps={props}
              >
                {children}
              </OverflowTooltipTrigger>
            );
          }}
        </TooltipTrigger>
        <TooltipContent>{resolvedTooltip}</TooltipContent>
      </Tooltip>
    );
  }

  return content;
}

"use client";

import { Children, type ComponentPropsWithRef, isValidElement, type ReactNode } from "react";
import { useComposedRefs } from "@/hooks/use-composed-refs";
import { useOverflowItems } from "@/hooks/use-overflow-items";
import { cn } from "@/lib/utils";

/** Props for overflow indicator render. */
export interface OverflowIndicatorRenderProps {
  /** Numeric count rendered by the component. */
  count: number;
}

/** Root - text mode by default; set mode="items" for fitting child items. */
export type OverflowIndicatorRender =
  | ((props: OverflowIndicatorRenderProps) => ReactNode)
  | ReactNode;

const hiddenClass = "invisible absolute pointer-events-none";

/** Props for overflow items. */
export interface OverflowItemsProps extends Omit<ComponentPropsWithRef<"div">, "children"> {
  /** String to clamp (text mode) or items to measure (items mode). */
  children: ReactNode;
  /** Items mode only. Render function or static node shown when items overflow. */
  indicator?: OverflowIndicatorRender;
  /** Items mode only. Tailwind gap class applied between items and indicator. */
  gap?: string;
  /** Accessible name for the overflow indicator. Defaults to `${count} more items`. */
  getOverflowLabel?: (count: number) => string;
}

function DefaultBadge() {
  return (
    <span
      aria-hidden="true"
      className="inline-flex items-center border border-dashed border-foreground/30 px-1.5 py-0.5 font-mono text-2xs text-muted-foreground"
    >
      …
    </span>
  );
}

function IndicatorDisplay({
  indicator,
  count,
}: {
  indicator?: OverflowIndicatorRender;
  count: number;
}) {
  if (typeof indicator === "function") {
    return <>{indicator({ count })}</>;
  }
  return <>{indicator ?? <DefaultBadge />}</>;
}

/** Root - text mode by default; set mode="items" for fitting child items. */
export function OverflowItems({
  children,
  indicator,
  gap = "gap-1",
  className,
  getOverflowLabel,
  ref,
  ...props
}: OverflowItemsProps) {
  const items = Children.toArray(children);
  const {
    ref: overflowRef,
    visibleCount,
    overflowCount,
  } = useOverflowItems({
    itemCount: items.length,
  });
  const composedRef = useComposedRefs(overflowRef, ref);

  return (
    <div
      ref={composedRef}
      className={cn("relative flex items-center overflow-clip", gap, className)}
      {...props}
    >
      {items.map((item, i) => (
        <div
          key={isValidElement(item) ? item.key : i}
          className={cn("shrink-0", i >= visibleCount && hiddenClass)}
          inert={i >= visibleCount || undefined}
        >
          {item}
        </div>
      ))}
      {/* biome-ignore lint/a11y/useAriaPropsSupportedByRole: role is conditionally "status" (Biome cannot resolve the ternary); aria-label is applied in the same branch and is valid for the status role. */}
      <div
        className={cn("shrink-0", overflowCount === 0 && hiddenClass)}
        role={overflowCount > 0 ? "status" : undefined}
        aria-label={
          overflowCount > 0
            ? (getOverflowLabel?.(overflowCount) ?? `${overflowCount} more items`)
            : undefined
        }
        inert={overflowCount === 0 || undefined}
      >
        <IndicatorDisplay indicator={indicator} count={overflowCount} />
      </div>
    </div>
  );
}
